import re

with open("raw_training_prompts.md", "r", encoding="utf-8") as f:
    content = f.read()

for scenario_num, response_text in RESPONSES.items():
    # Find the exact empty response block for this scenario
    # Pattern: ### Expected Response *(Fill In)*\n\n```\n\n```
    # We need to find the N-th occurrence
    pattern = r'(### Expected Response \*\(Fill In\)\*\n\n```)\n(\n```)'
    
    # Count and replace the specific occurrence
    count = [0]
    
    def replace_nth(match):
        count[0] += 1
        if count[0] == scenario_num:
            return match.group(1) + "\n" + response_text + "\n" + match.group(2)
        return match.group(0)
    
    content = re.sub(pattern, replace_nth, content, count=scenario_num)

with open("raw_training_prompts.md", "w", encoding="utf-8") as f:
    f.write(content)

print(f"✅ Injected {len(RESPONSES)} responses into raw_training_prompts.md")

# Verify
filled = content.count("### Expected Response") 
empty = content.count("```\n\n```")
print(f"   Total response blocks: {filled}")
print(f"   Still empty blocks: {empty}")
